function poolFits(key) { const pl = GAMEDATA.pools[key]; if (!pl) return false; const op = new Set(); openSlotsLeft().forEach(s => s.elig.forEach(p => op.add(p))); return pl.some(p => op.has(p.p)); }
function randomSpin(keepTeam, keepYear) {
    let team = keepTeam ? state.spin.team : null, year = keepYear ? state.spin.year : null, tries = 0;
    /* Exclude the currently-shown team/year from re-roll candidates when we're randomizing that dimension. */
    const excludeTeam = (!keepTeam && state.spin) ? state.spin.team : null;
    const excludeYear = (!keepYear && state.spin) ? state.spin.year : null;
    const teamPool = excludeTeam ? ALL_TEAMS.filter(t => t !== excludeTeam) : ALL_TEAMS;
    const yearPool = excludeYear ? ALL_YEARS.filter(t => t !== excludeYear) : ALL_YEARS;
    while (tries++ < 500) {
        const t = team || teamPool[Math.floor(Math.random() * teamPool.length)]; const ysAll = teamYears[t]; const ys = (excludeYear && !keepYear) ? ysAll.filter(y => y !== excludeYear) : ysAll; const ysPick = ys.length ? ys : ysAll; const y = year || ysPick[Math.floor(Math.random() * ysPick.length)];
        if (poolFits(t + "|" + y) && Math.random() < REGION_LIKELIHOODS.get(t)) return { team: t, year: y };
    } return { team: team || ALL_TEAMS[0], year: year || teamYears[ALL_TEAMS[0]][0] };
}
function doSpin(keepTeam, keepYear) {
    $("spin-btn").disabled = true; $("reel-team").classList.add("spinning", "lit"); $("reel-year").classList.add("spinning", "lit");
    const target = randomSpin(keepTeam, keepYear); let n = 0;
    const iv = setInterval(() => {
        $("rv-team").textContent = keepTeam ? target.team : ALL_TEAMS[Math.floor(Math.random() * ALL_TEAMS.length)];
        $("rv-year").textContent = keepYear ? target.year : ALL_YEARS[Math.floor(Math.random() * ALL_YEARS.length)];
        if (++n > 12) {
            clearInterval(iv); $("rv-team").textContent = target.team; $("rv-year").textContent = target.year;
            $("reel-team").classList.remove("spinning"); $("reel-year").classList.remove("spinning"); state.spin = target; setTimeout(enterDraft, 1400);
        }
    }, 100);
}
