$("rr-season").onclick = () => { if (!state.rrYear) return; state.rrYear = false; $("rr-season").disabled = true; showSpinView(); $("rv-team").textContent = state.spin.team; $("reel-team").classList.add("lit"); doSpin(true, false); };
$("filters").onclick = e => { const b = e.target.closest(".fbtn"); if (!b) return; document.querySelectorAll(".fbtn").forEach(x => x.classList.remove("active")); b.classList.add("active"); state.filter = b.dataset.f; updateSortOptions(); renderPool(); };
